const body = items[0].json.body;
const user = body.user_profile;
const scheme = body.scheme;

// Generate dynamic, context-specific draft stages
const draft_stages = [
  `Stage 1: Document Upload & OCR. Upload your Aadhaar or Income Certificate. We will auto-fill your name (${user.name || 'Not Specified'}) and annual income (${user.annual_income || 'Not Specified'}).`,
  `Stage 2: Review Pre-filled Form. Review all extracted details: Name: ${user.name}, State: ${user.state}, Income: ${user.annual_income}, Caste: ${user.caste_category || 'General'}.`,
  `Stage 3: Auto-fill Official Portal. Click the Bookmarks Autofill Tool to login to ${scheme.source_url} and fill out the fields automatically.`
];

return [{
  json: {
    draft_stages,
    user_profile: user,
    scheme: scheme
  }
}];

// Browser Automation (Puppeteer / Playwright) simulation script for n8n code execution
// This runs in n8n environments equipped with puppeteer to open the portal and fill the form
const profile = items[0].json.user_profile;
const scheme = items[0].json.scheme;

const puppeteerScript = `
const puppeteer = require('puppeteer');
(async () => {
  const browser = await puppeteer.launch({ headless: false });
  const page = await browser.newPage();

  console.log('Navigating to portal:', '${scheme.source_url}');
  await page.goto('${scheme.source_url}', { waitUntil: 'networkidle2' });

  // Step 1: Handle login if required
  const loginButton = await page.$('a[href*="login"], button[id*="login"]');
  if (loginButton) {
    await loginButton.click();
    await page.waitForNavigation({ waitUntil: 'networkidle2' });
    // Prompt user / caseworker to log in or enter OTP manually
    console.log('Caseworker: Please log in or enter OTP on the screen.');
  }

  // Step 2: Navigate to registration / application form
  await page.waitForSelector('input', { timeout: 60000 });

  // Step 3: Enter profile details dynamically
  const nameInput = await page.$('input[name*="name"], input[id*="name"]');
  if (nameInput) await nameInput.type('${profile.name || ""}');

  const incomeInput = await page.$('input[name*="income"], input[id*="income"]');
  if (incomeInput) await incomeInput.type('${profile.annual_income || ""}');

  const stateInput = await page.$('select[name*="state"], select[id*="state"]');
  if (stateInput) {
    await stateInput.select('${profile.state || ""}');
  }

  console.log('Form filling automation completed for current step.');
})();
`;

return [{
  json: {
    ...items[0].json,
    automation_script: puppeteerScript
  }
}];
